import { useEffect, useMemo, useState } from "react";
import { getCustomers } from "../services/api";
import "../styles/Dashboard.css";

function Dashboard() {
  const [customers, setCustomers] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Loads customer list once to build summary cards.
    const loadCustomers = async () => {
      try {
        const response = await getCustomers();
        setCustomers(response.data || []);
      } catch (error) {
        setCustomers([]);
      } finally {
        setLoading(false);
      }
    };

    loadCustomers();
  }, []);

  const totalCustomers = useMemo(() => customers.length, [customers]);
  const totalUdhaar = useMemo(
    () => customers.reduce((sum, customer) => sum + Math.max(customer.totalBalance || 0, 0), 0),
    [customers]
  );

  return (
    <main className="dashboard-page py-4">
      <div className="container">
        <section className="dashboard-header mb-4">
          <h1 className="dashboard-title">Shop Overview</h1>
          <p className="dashboard-subtitle">
            Track your outstanding udhaar and customer base at a glance.
          </p>
        </section>

        {loading ? (
          <div className="dashboard-loading card p-4">Loading dashboard data...</div>
        ) : (
          <section className="row g-4">
            <div className="col-md-6">
              <article className="summary-card udhaar-card">
                <p className="summary-label">Total Udhaar</p>
                <h2 className="summary-value">Rs {totalUdhaar.toLocaleString("en-IN")}</h2>
              </article>
            </div>
            <div className="col-md-6">
              <article className="summary-card customer-card">
                <p className="summary-label">Total Customers</p>
                <h2 className="summary-value">{totalCustomers}</h2>
              </article>
            </div>
          </section>
        )}
      </div>
    </main>
  );
}

export default Dashboard;
